import { useParams, Link } from 'react-router-dom';
import { BookOpen, ArrowLeft } from 'lucide-react';

const subjectsByDepartment = {
  cse: [
    { id: 'ds', name: 'Data Structures', semester: 3 },
    { id: 'os', name: 'Operating Systems', semester: 4 },
    { id: 'cn', name: 'Computer Networks', semester: 5 },
    { id: 'dbms', name: 'Database Management Systems', semester: 4 },
    { id: 'se', name: 'Software Engineering', semester: 6 }
  ],
  ece: [
    { id: 'signals', name: 'Signals & Systems', semester: 4 },
    { id: 'dsp', name: 'Digital Signal Processing', semester: 5 },
    { id: 'comm', name: 'Communication Systems', semester: 6 }
  ],
  eee: [
    { id: 'circuits', name: 'Electric Circuits', semester: 3 },
    { id: 'machines', name: 'Electric Machines', semester: 4 },
    { id: 'power', name: 'Power Systems', semester: 5 }
  ],
  me: [
    { id: 'thermo', name: 'Thermodynamics', semester: 3 },
    { id: 'fluid', name: 'Fluid Mechanics', semester: 4 },
    { id: 'heat', name: 'Heat Transfer', semester: 5 }
  ],
  ce: [
    { id: 'structures', name: 'Structural Analysis', semester: 4 },
    { id: 'concrete', name: 'Concrete Technology', semester: 5 },
    { id: 'geo', name: 'Geotechnical Engineering', semester: 6 }
  ]
};

const departmentNames = {
  cse: 'Computer Science Engineering',
  ece: 'Electronics & Communication Engineering',
  eee: 'Electrical & Electronics Engineering',
  me: 'Mechanical Engineering',
  ce: 'Civil Engineering'
};

const SubjectSelection = () => {
  const { deptId } = useParams();
  const subjects = subjectsByDepartment[deptId] || [];
  const deptName = departmentNames[deptId];

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-4xl mx-auto px-4">
        <div className="flex items-center mb-6">
          <Link to="/dashboard" className="mr-4 p-2 hover:bg-gray-200 rounded-lg">
            <ArrowLeft className="w-5 h-5" />
          </Link>
          <div>
            <h1 className="text-3xl font-bold text-gray-900">{deptName}</h1>
            <p className="text-gray-600">Select a subject to access resources</p>
          </div>
        </div>

        <div className="grid md:grid-cols-2 gap-4">
          {subjects.map((subject) => (
            <Link
              key={subject.id}
              to={`/subject/${deptId}/${subject.id}`}
              className="bg-white rounded-lg shadow-md hover:shadow-lg transition-shadow p-6 border border-gray-200 hover:border-blue-300"
            >
              <div className="flex items-center justify-between">
                <div className="flex items-center space-x-4">
                  <div className="w-10 h-10 bg-blue-100 rounded-lg flex items-center justify-center">
                    <BookOpen className="w-5 h-5 text-blue-600" />
                  </div>
                  <div>
                    <h3 className="font-semibold text-gray-900">{subject.name}</h3>
                    <p className="text-sm text-gray-500">Semester {subject.semester}</p>
                  </div>
                </div>
              </div>
            </Link>
          ))}
        </div>
      </div>
    </div>
  );
};

export default SubjectSelection;
